import{_ as t,o as a,c as s,ag as i}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"泛型类型","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/generic.md","filePath":"zh/guide/generic.md","lastUpdated":1782689832000}'),r={name:"zh/guide/generic.md"};function o(n,e,d,l,p,h){return a(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="泛型类型" tabindex="-1">泛型类型 <a class="header-anchor" href="#泛型类型" aria-label="Permalink to &quot;泛型类型&quot;">​</a></h1><p>EasyYapi 会自动解析 API 文档中的泛型类型——<code>Result&lt;User&gt;</code> 会被展开为一个 <code>Result</code> 对象，其 <code>data</code> 字段具有 <code>User</code> 的结构，无需额外配置。</p><h2 id="覆盖返回类型" tabindex="-1">覆盖返回类型 <a class="header-anchor" href="#覆盖返回类型" aria-label="Permalink to &quot;覆盖返回类型&quot;">​</a></h2><p>如果声明的返回类型不能反映你希望文档化的内容（例如方法返回 <code>Object</code> 或原始类型），用 <code>method.return</code> 覆盖为具体的泛型类型：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">method.return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.example.Result&lt;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> + it.returnType().name() + </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&gt;&quot;</span></span></code></pre></div><h2 id="把-return-挂到包装类型的字段上" tabindex="-1">把 <code>@return</code> 挂到包装类型的字段上 <a class="header-anchor" href="#把-return-挂到包装类型的字段上" aria-label="Permalink to &quot;把 `@return` 挂到包装类型的字段上&quot;">​</a></h2><p><code>method.return.main</code> <strong>不会</strong>改变返回类型——它指定响应类型内部的<strong>字段名</strong>，方法的 <code>@return</code> 文档注释会挂到该字段上：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">method.return.main</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;data&quot;</span></span></code></pre></div><p>对于 <code>Result&lt;User&gt;</code>，应用上述规则后，<code>@return</code> 注释会挂到 <code>data</code> 字段上，而不是根 <code>Result</code> 对象上。</p><h2 id="类型转换" tabindex="-1">类型转换 <a class="header-anchor" href="#类型转换" aria-label="Permalink to &quot;类型转换&quot;">​</a></h2><p>用 <code>json.rule.convert</code> 转换类型：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">json.rule.convert</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:it.type().name()==</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;java.util.Date&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> =&gt; java.lang.String</span></span></code></pre></div><p>详见 <a href="/zh/settings/rules/json_rule_convert">json.rule.convert</a>、<a href="/zh/settings/rules/method_return">method.return</a> 和 <a href="/zh/settings/rules/method_return_main">method.return.main</a>。</p>',13)])])}const g=t(r,[["render",o]]);export{u as __pageData,g as default};
